1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with 2 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
19	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
20	    expect(result).not.toContainEqual([1, 1]);
21	  });
22	  it("should bring a dead cell to life with exactly 3 live neighbors (reproduction)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
24	    expect(result).toContainEqual([1, 1]);
25	  });
26	  it("should keep a 2x2 block unchanged (still life)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
28	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
29	    expect(result.length).toBe(4);
30	  });
31	  it.todo("should oscillate a vertical blinker to horizontal (oscillator)");
32	  it.todo("should handle negative coordinates");
33	});
34

1	type Cell = [number, number];
2	
3	const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;
4	
5	const neighborOffsets: Cell[] = [
6	  [-1, -1], [0, -1], [1, -1],
7	  [-1, 0], [1, 0],
8	  [-1, 1], [0, 1], [1, 1],
9	];
10	
11	const getNeighbors = (cell: Cell): Cell[] =>
12	  neighborOffsets.map(([dx, dy]) => [cell[0] + dx, cell[1] + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, liveKeys: Set<string>): number =>
15	  getNeighbors(cell).filter((neighbor) => liveKeys.has(cellKey(neighbor))).length;
16	
17	const survives = (liveNeighbors: number): boolean =>
18	  liveNeighbors === 2 || liveNeighbors === 3;
19	
20	const uniqueCells = (cells: Cell[]): Cell[] => {
21	  const seen = new Set<string>();
22	  return cells.filter((cell) => {
23	    const key = cellKey(cell);
24	    if (seen.has(key)) return false;
25	    seen.add(key);
26	    return true;
27	  });
28	};
29	
30	export const nextGeneration = (cells: Cell[]): Cell[] => {
31	  const liveKeys = new Set(cells.map(cellKey));
32	  const survivors = cells.filter((cell) => survives(countLiveNeighbors(cell, liveKeys)));
33	  const deadNeighbors = uniqueCells(cells.flatMap(getNeighbors))
34	    .filter((cell) => !liveKeys.has(cellKey(cell)));
35	  const reborn = deadNeighbors.filter((cell) => countLiveNeighbors(cell, liveKeys) === 3);
36	  return [...survivors, ...reborn];
37	};
